    "balance_sheet": { "Cash": 0, "Accounts_Receivable": 0, "Inventory": 0, "Total_Current_Assets": 0, "PPE_Net": 0, "Total_Assets": 0, "Accounts_Payable": 0, "Short_Term_Debt": 0, "Total_Current_Liabilities": 0, "Long_Term_Debt": 0, "Total_Equity": 0 },
