const rnd=(a,b,dp=0)=>{const v=a+Math.random()*(b-a);return dp?parseFloat(v.toFixed(dp)):Math.round(v);};const pick=arr=>arr[Math.floor(Math.random()*arr.length)];const names=["Sarah Chen","Marcus Webb","Elena Volkov","James Okafor","Priya Sharma","David Kim","Aisha Nkosi","Carlos Reyes"];const firms=["Capital Partners","Asset Management","Wealth Advisors","Investment Group","Securities"];const pname=()=>pick(names);const pfirm=()=>pname().split(" ")[1]+" "+pick(firms);// ─── CFA INSTITUTE ETHICS IN PRACTICE CASES ─────────────────────────────────
